function norm(s: string): string {
  return (s || "").toLowerCase().replace(/\s+/g, "");
}

/**
 * Autocomplete suggestions for a typed prefix. The user's OWN past dishes (at
 * this restaurant, then anywhere) rank first; the curated vocabulary fills in.
 */
export function suggestDishes(
  prefix: string,
  pastAtRestaurant: string[],
  pastAnywhere: string[],
  limit = 8,
  cuisineTags: string[] = []
): Dish[] {
  const q = norm(prefix);
  const seen = new Set<string>();
  const out: Dish[] = [];
  const push = (name: string) => {
    if (!name || seen.has(name)) return;
    seen.add(name);
    out.push(byName.get(name) ?? { name, tasteTags: [] });
  };
  const match = (name: string) => !q || norm(name).includes(q);

  // Own history first (unchanged).
  for (const n of pastAtRestaurant) if (match(n)) push(n);
  for (const n of pastAnywhere) if (match(n)) push(n);

  // Vocabulary: when we know the restaurant's cuisine (from its name), show
  // matching-cuisine dishes — a 日本料理 shouldn't default to 菠蘿油/餐蛋麵.
  const cui = new Set(cuisineTags);
  const vocab = VOCAB.filter((d) => match(d.name));
  if (cui.size) {
    const hit = vocab.filter((d) => d.tasteTags.some((t) => cui.has(t)));
    for (const d of hit) push(d.name);
    // Only when the user is actively typing do we fall back to other cuisines
    // (free typing must never be blocked); an empty box stays cuisine-scoped.
    if (q) for (const d of vocab) if (!hit.includes(d)) push(d.name);
  } else {
    for (const d of vocab) push(d.name);
  }
  return out.slice(0, limit);
}

/** Look up taste tags for a known dish name (empty if user-invented). */
export function tagsFor(name: string): string[] {
  return byName.get(name)?.tasteTags ?? [];
}
