// 層 B — short-term SESSION memory (「今次意圖」). 方案 A: client-only, ephemeral.
//
// Lives in sessionStorage → cleared automatically when the tab closes, and treated
// as a NEW session after 30 min idle. It NEVER touches the long-term taste store
// (localStorage: dm.memories / dm.tasteSeed). A「今次唔想食辣」is a temporary filter,
// not a permanent taste — this file has no import of, and never writes, any taste key.
// $0, server stays stateless, the「記憶只存喺你部機」privacy promise is intact.
import type { SuggestIntent } from "./suggestClient";

// The 8 intent facets a user can toggle. Stored as an ORDERED list (later toggles
// win for preferType / leadBucket — 「後到覆蓋」). `near` is NOT stored here; it maps
// to an area pin (needs the resolved home district, set via setSessionArea).
type FacetIntent = Exclude<SuggestIntent, "near">;

export interface SessionState {
  sessionId: string;
  startedAt: number;
  updatedAt: number;
  turns: number;
  intent: FacetIntent[]; // ordered active facets
  areaOverride?: string; // FEHD district pinned by 近啲 / a typed area
  areaLabel?: string; // colloquial label for the active-filter chip
  dismissed: string[]; // 今次剔走 — session-only (下 session 復活)
}

// Derived, ready-to-apply shape consumed by buildSuggestion.
export interface SessionSpec {
  excludeCuisines: string[];
  preferType?: "RL" | "RR";
  leadBucket?: "fresh" | "quick";
  areaOverride?: string;
  areaLabel?: string;
}

const KEY = "dm.session";
const IDLE_MS = 30 * 60 * 1000; // idle 30 分鐘 → reset

function uuid(): string {
  try {
    if (typeof crypto !== "undefined" && crypto.randomUUID) return crypto.randomUUID();
  } catch { /* ignore */ }
  return "s-" + Math.random().toString(36).slice(2) + Date.now().toString(36);
}

function fresh(): SessionState {
  const now = Date.now();
  return { sessionId: uuid(), startedAt: now, updatedAt: now, turns: 0, intent: [], dismissed: [] };
}

function read(): SessionState {
  try {
    const raw = sessionStorage.getItem(KEY);
    if (!raw) return fresh();
    const s = JSON.parse(raw) as SessionState;
    if (!s || typeof s !== "object") return fresh();
    // idle → treat as a brand-new session (今次意圖 decays)
    if (Date.now() - (s.updatedAt || 0) > IDLE_MS) return fresh();
    s.intent = Array.isArray(s.intent) ? s.intent : [];
    s.dismissed = Array.isArray(s.dismissed) ? s.dismissed : [];
    return s;
  } catch {
    return fresh();
  }
}

function write(s: SessionState): void {
  try {
    s.updatedAt = Date.now();
    sessionStorage.setItem(KEY, JSON.stringify(s));
  } catch { /* ignore (private mode etc.) */ }
}

export function getSession(): SessionState {
  return read();
}

/** Toggle-on an intent facet (accumulates; sticky until ✕ or reset). */
export function addSessionIntent(i: SuggestIntent): void {
  if (i === "near") return; // area pin handled by setSessionArea
  const s = read();
  s.intent = [...s.intent.filter((x) => x !== i), i]; // move to end = highest precedence
  s.turns += 1;
  write(s);
}

/** Remove one active facet (its ✕ in the「今次生效中」bar). */
export function removeSessionIntent(i: FacetIntent): void {
  const s = read();
  s.intent = s.intent.filter((x) => x !== i);
  write(s);
}

/** Pin the district (近啲 → resolved home, or a typed area). */
export function setSessionArea(area: string, label: string): void {
  const s = read();
  s.areaOverride = area;
  s.areaLabel = label;
  write(s);
}

export function clearSessionArea(): void {
  const s = read();
  delete s.areaOverride;
  delete s.areaLabel;
  write(s);
}

/** 今次剔走 — session-only, does NOT touch permanent dm.suggestFeedback. */
export function addSessionDismiss(id: string): void {
  const s = read();
  if (!s.dismissed.includes(id)) s.dismissed.push(id);
  write(s);
}

export function getSessionDismissed(): string[] {
  return read().dismissed;
}

/** ⟳ 今次重新開始 — wipe the session (start fresh). */
export function clearSession(): void {
  try {
    sessionStorage.removeItem(KEY);
  } catch { /* ignore */ }
}

/** Any active「今次意圖」worth surfacing in the filter bar? */
export function hasActiveSession(): boolean {
  const s = read();
  return s.intent.length > 0 || !!s.areaOverride;
}

/** Derive the ready-to-apply spec from the ordered facets. Later facets override
 *  earlier ones for preferType / leadBucket (「後到覆蓋」); excludeCuisines union. */
export function sessionSpec(): SessionSpec {
  const s = read();
  const excludeCuisines: string[] = [];
  const spec: SessionSpec = { excludeCuisines, areaOverride: s.areaOverride, areaLabel: s.areaLabel };
  for (const f of s.intent) {
    switch (f) {
      case "no-spicy": pushNew(excludeCuisines, ["辣", "火鍋"]); break;
      case "no-noodle": pushNew(excludeCuisines, ["麵", "拉麵", "米線"]); break;
      case "long-sit": spec.preferType = "RL"; break;
      case "cheap": case "less-queue": spec.preferType = "RR"; spec.leadBucket = "quick"; break;
      case "switch": case "fresh": spec.leadBucket = "fresh"; break;
    }
  }
  return spec;
}

function pushNew(arr: string[], items: string[]): void {
  for (const i of items) if (!arr.includes(i)) arr.push(i);
}
